impl.spec_text:
spec fn cintf(m: int, n: int) -> bool {
    true
}

proof fn cnat() {
    assert(cintf(-10, -10));
    assert(choose_tuple::<(nat, nat), _>(|m: nat, n: nat| cintf(m as int, n as int) && m < 0 && n < 0).0 < 0); // FAILS
}

